import "fmt"

func swap(x, y *int) {
	*x, *y = *y, *x
}

func main() {
	x := 3
	y := 2
	fmt.Println(x, y)
	swap(&x, &y)
	fmt.Println(x, y)
}

public class SwapTwoVariables {
    public static int[] swap(int a, int b) {
        return new int[]{b, a};
    }
}

fun swap(a: Int, b: Int): IntArray {
    return intArrayOf(b, a)
}

object Swap {

  def swap(x: Int, y: Int) = {
    (y,x)
  }

  def main(args: Array[String]): Unit = {
    var (x, y) = (10,6)
    var swapped = swap(x,y)
    x = swapped._1
    y = swapped._2
    println(x, y)
  }

}

func swap(_ a: Int, _ b: Int) -> [Int] {
    [b, a]
}

/**
 * Swaping two variables using a temporary variable
 * @param {Number} num1
 * @param {Number} num2
 * @return {Array} variables with swapped values in form of an array
 */
const swap = (num1, num2) => {
  const temp = num1;
  num1 = num2;
  num2 = temp;
  return [num1, num2];
};

module.exports = swap;
